ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/jobpostings#>
PREFIX p: <http://ambrosia.example.org/jobpostings/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE attachment {
  high: { SELECT DISTINCT ?o0 WHERE {
  {
    ?tour_guide a :Tour_Guide .
    ?agency a :Agency .
    ?tour_guide p:hasAgency ?agency .
    ?tour_guide p:guideName ?guidename .
    ?agency p:name ?name_f .
    FILTER(STR(?name_f) = "Expedia")
    BIND(?guidename AS ?o0)
  }
  UNION
  {
    ?travel_agent a :TravelAgents .
    ?agency a :Agency .
    ?travel_agent p:hasAgency ?agency .
    ?travel_agent p:agentName ?agentname .
    ?agency p:name ?name_f .
    FILTER(STR(?name_f) = "Expedia")
    BIND(?agentname AS ?o0)
  }
} }
  low: { SELECT DISTINCT ?o0 WHERE {
  {
    ?tour_guide a :Tour_Guide .
    ?agency a :Agency .
    ?tour_guide p:hasAgency ?agency .
    ?tour_guide p:guideName ?guidename .
    BIND(?guidename AS ?o0)
  }
  UNION
  {
    ?travel_agent a :TravelAgents .
    ?agency a :Agency .
    ?travel_agent p:hasAgency ?agency .
    ?travel_agent p:agentName ?agentname .
    ?agency p:name ?name_f .
    FILTER(STR(?name_f) = "Expedia")
    BIND(?agentname AS ?o0)
  }
} }
}
